import React from "react";
import {Switch, Route} from "react-router-dom";
import Home from "../Home";
import About from "../About";
import Blog from "../xps/Blog";
import { BlogPost } from "../xps/BlogPost";
import {getDocFromFirebase} from "./setupFB"


function createBlogSwitches(BlogPostsJSON){

    let pathnames = BlogPostsJSON.map(element => "/blog/"+element.id);
    return(
        BlogPostsJSON.map((element, index) =>
            (
            <Route path={pathnames[index]}>
                <BlogPost title={element.vals.title} body={element.vals.body} />
            </Route>)
            )
    );
}




class SwitchHandler extends React.Component {

    async set_state_json(){
        const res_array = await getDocFromFirebase(this.props.fb.db);
        this.setState({postJSONs: res_array});
    }

    constructor(props) {
        super(props);
        this.state = {postJSONs: []};
        this.set_state_json();
    }

    render(){
        return(
            <Switch>
                <Route exact path="/" component={Home} />
                <Route exact path="/about" component={About}/>
                <Route exact path="/blog">
                    <Blog json={this.state.postJSONs}/>
                </Route>
                {createBlogSwitches(this.state.postJSONs)}
            </Switch>
        );
    }
}



export default SwitchHandler;