  export async function getDocFromFirebase(db){
    const posts = [];
    try {
      const querySnapshot = await getDocs(collection(db, "blogPosts"));
      for(const file of querySnapshot.docs){
          const id = file.id;
          const file_data = file.data();
          posts.push({id: id, vals: file_data});
      }
      
    }
    catch(e){
      console.log("Error", e);
    }
    finally{
        return(posts);   
    } 
  }