import React from 'react';
import {Switch, Route, Link} from "react-router-dom";
import { BlogPost, BlogPostPreview } from './BlogPost';

class BlogContainer extends React.Component{
    constructor(props) {
        super(props);
    }

    render(){
        return(
            <div>
                {this.props.json.map(element => (<BlogPostPreview link ={element.id} title = {element.vals.title} />))}
            </div>
        );
    }

}


class Blog extends React.Component {

    constructor(props) {
        super(props);
    }


    render(){
        return(
            <header className="App-header">
                <BlogContainer json={this.props.json} />
                This will be a blog page!
            </header>
        );
    }
}

export default Blog;